<?php require "vendor/autoload.php"; use Symfony\Component\Dotenv\Dotenv; (new Dotenv())->bootEnv(__DIR__."/.env"); $client = Symfony\Component\HttpClient\HttpClient::create(); $service = new App\Service\HolidayService($client, $_ENV["ABSTRACT_HOLIDAYS_API_KEY"], __DIR__."/var/cache"); $countries = ["TR", "GB", "ES", "IT"]; foreach ($countries as $c) { $h = $service->getHoliday($c, new \DateTime("2026-04-23")); if ($h) echo "$c: " . $h["name"] . "\n"; } ?>
